def incremovableSubarrayCount(nums):
    n = len(nums)
    count = 0

    # Check all possible subarrays
    for i in range(n):
        for j in range(i, n):
            # Build array after removing subarray nums[i:j+1]
            remaining = nums[:i] + nums[j+1:]

            # Check if remaining is strictly increasing
            is_increasing = True
            for k in range(1, len(remaining)):
                if remaining[k] <= remaining[k-1]:
                    is_increasing = False
                    break

            if is_increasing:
                count += 1

    return count
